		$templateCode = str_replace('<%%URLVALUE(utedb_col_tf)%%>', urlencode($urow['utedb_col_tf']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(utedb_delta_flag)%%>', safe_html($urow['utedb_delta_flag']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(utedb_delta_flag)%%>', html_attr($row['utedb_delta_flag']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_delta_flag)%%>', urlencode($urow['utedb_delta_flag']), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_created)%%>', safe_html($urow['utedb_created']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_created)%%>', urlencode($urow['utedb_created']), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_updated)%%>', safe_html($urow['utedb_updated']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_updated)%%>', urlencode($urow['utedb_updated']), $templateCode);
	} else {
		$templateCode = str_replace('<%%VALUE(utedb_id)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_id)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_madb)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_madb)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_proof_image)%%>', 'blank.gif', $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_ai_audit)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_ai_audit)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_pc_audit)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_pc_audit)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_rda_audit)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_rda_audit)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_bb_audit)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_bb_audit)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_car)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_car)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_car_vid)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_car_vid)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_col_tf)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_col_tf)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_delta_flag)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_delta_flag)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_created)%%>', '<%%creationTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_created)%%>', urlencode('<%%creationTimestamp%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(utedb_updated)%%>', '<%%editingTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(utedb_updated)%%>', urlencode('<%%editingTimestamp%%>'), $templateCode);
	}

	// process translations
	$templateCode = parseTemplate($templateCode);

	// clear scrap
	$templateCode = str_replace('<%%', '<!-- ', $templateCode);
	$templateCode = str_replace('%%>', ' -->', $templateCode);

	// hide links to inaccessible tables
	if(Request::val('dvprint_x') == '') {
		$templateCode .= "\n\n<script>\$j(function() {\n";
		$arrTables = getTableList();
		foreach($arrTables as $name => $caption) {
			$templateCode .= "\t\$j('#{$name}_link').removeClass('hidden');\n";
			$templateCode .= "\t\$j('#xs_{$name}_link').removeClass('hidden');\n";
		}

		$templateCode .= $jsReadOnly;
		$templateCode .= $jsEditable;

		if(!$hasSelectedId) {
			$templateCode.="\n\tif(document.getElementById('utedb_car_vidEdit')) { document.getElementById('utedb_car_vidEdit').style.display='inline'; }";
			$templateCode.="\n\tif(document.getElementById('utedb_car_vidEditLink')) { document.getElementById('utedb_car_vidEditLink').style.display='none'; }";
		}

		$templateCode.="\n});</script>\n";
	}

	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';

	$templateCode .= "\tutedb_madb_update_autofills$rnd1 = function() {\n";
	$templateCode .= "\t\t\$j.ajax({\n";
	if($dvprint) {
		$templateCode .= "\t\t\turl: 'utedb_autofill.php?rnd1=$rnd1&mfk=utedb_madb&id=' + encodeURIComponent('".addslashes($row['utedb_madb'])."'),\n";
		$templateCode .= "\t\t\tcontentType: 'application/x-www-form-urlencoded; charset=" . datalist_db_encoding . "',\n";
		$templateCode .= "\t\t\ttype: 'GET'\n";
	} else {
		$templateCode .= "\t\t\turl: 'utedb_autofill.php?rnd1=$rnd1&mfk=utedb_madb&id=' + encodeURIComponent(AppGini.current_utedb_madb{$rnd1}.value),\n";
		$templateCode .= "\t\t\tcontentType: 'application/x-www-form-urlencoded; charset=" . datalist_db_encoding . "',\n";
		$templateCode .= "\t\t\ttype: 'GET',\n";
		$templateCode .= "\t\t\tbeforeSend: function() { \$j('#utedb_madb$rnd1').prop('disabled', true); },\n";
		$templateCode .= "\t\t\tcomplete: function() { " . (($allowInsert || $allowUpdate) ? "\$j('#utedb_madb$rnd1').prop('disabled', false); " : "\$j('#utedb_madb$rnd1').prop('disabled', true); ")." \$j(window).resize(); }\n";
	}
	$templateCode .= "\t\t});\n";
	$templateCode .= "\t};\n";
	if(!$dvprint) $templateCode .= "\tif(\$j('#utedb_madb_caption').length) \$j('#utedb_madb_caption').click(function() { utedb_madb_update_autofills$rnd1(); });\n";


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('utedb');
	if($hasSelectedId) {
		$jdata = get_joined_record('utedb', $selectedId);
		if($jdata === false) $jdata = get_defaults('utedb');
		$rdata = $row;
	}
	$templateCode .= loadView('utedb-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: utedb_dv
	if(function_exists('utedb_dv')) {
		$args = [];
		utedb_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}